import { readdirSync, writeFileSync } from "fs";
import { join } from "path";

const I18N_DIR = join(import.meta.dirname, "..", "src", "i18n");
const OUT_FILE = join(I18N_DIR, "en.ts");

const dirs = readdirSync(I18N_DIR, { withFileTypes: true })
  .filter((e) => e.isDirectory())
  .map((e) => e.name)
  .sort();

const lines = [
  "// AUTO-GENERATED by scripts/generate-en-barrel.mjs — do not edit manually",
  ...dirs.map((name) => `export { ${name} } from "./${name}/en";`),
  "",
];

writeFileSync(OUT_FILE, lines.join("\n"));
console.log(`[i18n] generated ${OUT_FILE} with ${dirs.length} modules`);
